import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/72-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/72-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/72-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 诸位大人以后通过使节提出其他建议,也会遇到麻烦。 皇帝这么急切地要实现借款计划,同时又那么不愿意达成任何明确的 协议。在我看来,其中原因正如我在之前多次在信中所提到的:根据帝国 会议的决定,皇帝不能与意大利的任何势力达成任何约定。因此,他一方 面急需资金,另一方面又不能提供任何抵押品。所以,他才试图通过中间 路线借钱。他已经和费拉拉尝试过同样的方法,但是没有成功。他对锡耶 纳也是这样做,潘多尔福付了钱,但除了单纯的诺言并没有得到任何回 报。确实,如果不是因为这个原因,既然陛下一开始看起来对诸位大人的 提议颇为满意,那么他要么会接受提议,要么会提出与诸位大人所提建议 类似的其他提议。因此,诸位大人必须决定如何处理这件事情。如果诸位 大人同意借款计划,并且相信皇帝的承诺,那么一笔少于25000达克特的 钱款应该就能满足他的需要。但是,如果诸位大人决定拒绝这个提议,那 么就要决定接下来应该采取什么行动,并把结论告诉我。我认为,诸位大 人现在就派遣使节到这里也未为不可,因为正如我前面所说,皇帝也这样 说过。而且,这样使节就可以超越皇帝的建议,在更远的北方与他会面。 就在今天,朗告诉我,诸位大人实在太过谨慎,而且从来不愿相信皇帝会 前往意大利。因为诸位大人如果相信,那么指定的使节早就应该到达这 里。虽然我适当地回应了这些说法,但是使节的到来应该会大大推进事情 的进展。除非如此,否则我不认为皇帝会改变主意。也许帝国会议并没有 绑住皇帝的手脚,而是他自己不愿意达成协议。因为他故意要求如此巨大 的一笔钱,虽然诸位大人现在没有答应,但只要诸位大人开始付款,那皇 帝就得胜了。可是,诸位大人是不会允许对方一再得逞的。〉 皇帝现在比我上次17日写信时更加积极备战了,步兵和重骑兵陆续经 过这里前往特伦特,其他部队可能经由别的路线开赴那里(那些我们没有 看到)。几天前,这里举行了一次500步兵和40炮手的检阅。从本月19日 到22日,大大小小约30门车载火炮,途经格里松到达瓦尔泰利纳谷地,然 后又被转运到特伦特。据说,皇帝已经和格里松联盟达成协议,他们将给",-1),e("p",null,"Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
